CREATE TABLE public.subscriptions (
  id                     uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id                uuid NOT NULL REFERENCES auth.users ON DELETE CASCADE,
  plan                   text NOT NULL DEFAULT 'free',
  status                 text NOT NULL DEFAULT 'active'
                           CHECK (status IN ('active','cancelled','past_due','trialing')),
  current_period_end     timestamptz,
  lemon_subscription_id  text UNIQUE,
  created_at             timestamptz NOT NULL DEFAULT now(),
  updated_at             timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.subscriptions ENABLE ROW LEVEL SECURITY;
CREATE POLICY "owner" ON public.subscriptions
  FOR ALL USING (auth.uid() = user_id);

-- Sync profiles.plan on every status change
CREATE OR REPLACE FUNCTION sync_profile_plan()
RETURNS TRIGGER LANGUAGE plpgsql SECURITY DEFINER AS $$
BEGIN
  UPDATE public.profiles SET plan = NEW.plan WHERE id = NEW.user_id;
  RETURN NEW;
END;
$$;
CREATE TRIGGER trg_sync_plan
  AFTER INSERT OR UPDATE ON public.subscriptions
  FOR EACH ROW EXECUTE FUNCTION sync_profile_plan();
